#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=710;

int n,ans=1;
pii p[N];

bool check(int a,int b,int c){
    return (p[a].y-p[b].y)*(p[b].x-p[c].x)==(p[b].y-p[c].y)*(p[a].x-p[b].x);
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&p[i].x,&p[i].y);
    for(int i=1;i<=n;i++)
        for(int j=i+1;j<=n;j++){
            int cnt=0;
            for(int k=1;k<=n;k++)
                cnt+=check(i,j,k);
            ans=max(ans,cnt);
        }
    printf("%d",ans);
    return 0;
}
